import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"56. Shift Work","description":"","frontmatter":{"title":"56. Shift Work","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["hours","shift-work","allowances"]},"headers":[],"relativePath":"ebas/mspp/hours-of-work/56-shift-work.md","filePath":"ebas/mspp/hours-of-work/56-shift-work.md"}'),s={name:"ebas/mspp/hours-of-work/56-shift-work.md"};function n(h,e,i,l,d,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_56-shift-work" tabindex="-1">56. Shift Work <a class="header-anchor" href="#_56-shift-work" aria-label="Permalink to &quot;56. Shift Work&quot;">​</a></h1><p><strong>56.1</strong> All Employees</p><p><strong>a.</strong> In addition to any other rates prescribed elsewhere in this Agreement, an Employee:</p><p><strong>(i)</strong> whose rostered hours or ordinary duty commence between 5.00 a.m. and 6.30 a.m. shall be paid the morning shift allowance in</p><p><strong>(ii)</strong> whose rostered hours or ordinary duty finish between 6.00 p.m. and midnight shall be paid the afternoon shift allowance in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a> per rostered period of duty.</p><p><strong>(iii)</strong> working on any rostered hours of ordinary duty finishing on the day after commencing duty or commencing after midnight and before</p><p><strong>5.00</strong> a.m. shall be paid the night shift allowance in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a> per rostered period of duty.</p><p><strong>b.</strong> Provided further that in the case of an Employee who changes from working on one shift to working on another shift, the time of commencement of which differs by four hours or more from that of the first, they shall be paid an amount equal to the change of shift allowance in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a> on the occasion of each such change in addition to any amount payable under the preceding provisions of this clause.</p><p><strong>c.</strong> Clause 56.1b above does not apply either where the Employee requests a change to the roster which creates a change of shift as described in 56.1b or where the Employee has 48 hours off duty between successive shifts.</p><p><strong>d.</strong> The allowances payable pursuant to this clause shall be calculated to the nearest 5 cents, portions of a cent being disregarded.</p><p><strong>e.</strong> Shift Work allowances are set out in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>.</p><p><strong>f.</strong> In the case of Pharmacists, the hours for morning shift allowance shall be those as set out at 56.2 until FFPPOA 1 December 2022 after which they shall be as per this clause 56.1.</p><p><strong>56.2</strong> Pharmacists</p><p><strong>a.</strong> Until the FFPPOA 1 December 2022, in addition to any other rates prescribed in this Agreement, a Pharmacist whose rostered hours of ordinary duty commence between 6.30am and 8.00am shall be paid the morning shift allowance in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>.</p><p><strong>b.</strong> Effective from the FFPPOA 1 December 2022, the full terms of 56.1 will apply, save that, in the event that there are local arrangements for a Pharmacist to commence between 6.30am and 8.00am, as provided in clause 56.2a, and the Pharmacist is better off overall under that arrangement then the span and penalty at clause 56.1 would not apply. That is, the local arrangement would continue to apply to that Pharmacist.</p><p><strong>56.3</strong> Saturday and Sunday Work - All Employees Except Pharmacists</p><p><strong>a.</strong> Where Saturday or Sunday duties are required to be carried out in excess of the ordinary week’s work, such duties shall be paid for at the rate of double time.</p><p><strong>b.</strong> All rostered time of ordinary duty performed on a Saturday or on a Sunday shall be paid for at the rate of time and a half.</p><p><strong>c.</strong> If the Saturday or Sunday duty involves duty in excess of the prescribed rostered hours, the excess period shall be paid for at the rate of double time for Saturday and Sunday.</p><p><strong>d.</strong> The provisions of this subclause shall not apply to a Scientist - Director or Deputy Director.</p><p><strong>56.4</strong> Saturday and Sunday Work – Pharmacists</p><p><strong>a.</strong> Where a Pharmacist Employee is required to work on a Saturday or Sunday they shall be paid at the rate of double time.</p><p><strong>b.</strong> Where a Pharmacist performs ordinary hours on a Saturday or Sunday in accordance with <a href="/eba/ebas/mspp/hours-of-work/55-hours-of-work.html">clause 55.1</a>(d), the rates at clause 56.3(b) apply.</p><p>Plain language terms: shift penalty, shift loading, afternoon shift, night shift.</p>',24)])])}const u=a(s,[["render",n]]);export{f as __pageData,u as default};
